const fs = require('fs');
const path = require('path');
const Joi = require('joi');
const logger = require('../../../common/logger');

let cachedProblems;

const MAX_LIMIT = 50;

/**
 * Normalize tags filter into a lowercase array.
 * @param {string|Array<string>} rawTags
 * @returns {Array<string>}
 */
function normalizeTags(rawTags) {
  if (!rawTags && rawTags !== '') {
    return [];
  }
  if (typeof rawTags === 'string') {
    return rawTags.split(',').map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
  }
  if (Array.isArray(rawTags)) {
    return rawTags.map(t => t.toLowerCase());
  }
  return [];
}

/**
 * Load problems from data/problems.json
 * @returns {Array<Object>}
 */
function loadProblems() {
  if (!cachedProblems) {
    const filePath = path.join(__dirname, '..', '..', '..', 'data', 'problems.json');
    const content = fs.readFileSync(filePath, 'utf8');
    cachedProblems = JSON.parse(content);
  }
  return cachedProblems;
}

/**
 * Get problem by ID with extended component statistics.
 * @param {string} problemId
 * @returns {Object|null} problem with component stats or null if not found
 */
function getProblemWithStats(problemId) {
  const problems = loadProblems();
  const problem = problems.find(p => p.id === problemId);
  if (!problem) return null;

  // Aggregate component statistics
  const components = problem.components || [];
  const languageCounts = {};
  const statusCounts = {};
  let maxPoints = 0;

  components.forEach(c => {
    if (c.language) {
      languageCounts[c.language] = (languageCounts[c.language] || 0) + 1;
    }
    if (c.status) {
      statusCounts[c.status] = (statusCounts[c.status] || 0) + 1;
    }
    if (typeof c.points === 'number' && c.points > maxPoints) {
      maxPoints = c.points;
    }
  });

  return {
    ...problem,
    componentStats: {
      languageCounts,
      statusCounts,
      maxPoints,
    },
  };
}

